Step 1: Set Up the Backend
mkdir chatbot && cd chatbot
mkdir server && cd server
npm init -y
npm install express cors dotenv openaiserver/.env
OPENAI_API_KEY=your_openai_api_key_here
PORT=5000server/index.js
const express = require('express');
const cors = require('cors');
const OpenAI = require('openai');
require('dotenv').config();const app = express();
const PORT = process.env.PORT || 5000;app.use(cors());
app.use(express.json());const openai = new OpenAI({
apiKey: process.env.OPENAI_API_KEY,
});// System prompt — defines your bot's personality
const SYSTEM_PROMPT = {
role: 'system',
content: `You are a helpful, friendly assistant.
Keep your answers clear and concise.
If you don't know something, say so honestly.`,
};// POST /api/chat
// Body: { messages: [ { role, content }, ... ] }
app.post('/api/chat', async (req, res) => {
const { messages } = req.body; if (!messages || !Array.isArray(messages)) {
return res.status(400).json({ error: 'messages array is required' });
} try {
const completion = await openai.chat.completions.create({
model: 'gpt-4o-mini',
messages: [SYSTEM_PROMPT, ...messages],
max_tokens: 500,
temperature: 0.7,
}); const reply = completion.choices[0].message;
res.json({ message: reply }); } catch (error) {
console.error('OpenAI error:', error.message);
res.status(500).json({ error: 'Failed to get response from AI' });
}
});app.listen(PORT, () => {
console.log(`Server running on http://localhost:${PORT}`);
});Start the server:
node index.js
# Server running on http://localhost:5000Test it quickly with curl:
curl -X POST http://localhost:5000/api/chat \
-H "Content-Type: application/json" \
-d '{"messages": [{"role": "user", "content": "Hello!"}]}'
Step 2: Set Up the React Frontend
cd .. # back to chatbot/
npm create vite@latest client -- --template react
cd client
npm install
Step 3: Build the Chat UI
Replace src/App.jsx with the following:
src/App.jsx
import { useState, useRef, useEffect } from 'react';
import './App.css';const API_URL = 'http://localhost:5000/api/chat';function App() {
const [messages, setMessages] = useState([
{ role: 'assistant', content: 'Hi! I\'m your AI assistant. How can I help you today?' }
]);
const [input, setInput] = useState('');
const [isLoading, setIsLoading] = useState(false);
const bottomRef = useRef(null); // Auto-scroll to latest message
useEffect(() => {
bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
}, [messages]); const sendMessage = async () => {
const trimmed = input.trim();
if (!trimmed || isLoading) return; // Add user message to chat
const userMessage = { role: 'user', content: trimmed };
const updatedMessages = [...messages, userMessage];
setMessages(updatedMessages);
setInput('');
setIsLoading(true); try {
const res = await fetch(API_URL, {
method: 'POST',
headers: { 'Content-Type': 'application/json' },
// Send full conversation history so AI has memory
body: JSON.stringify({ messages: updatedMessages }),
}); if (!res.ok) throw new Error('Server error'); const data = await res.json();
setMessages(prev => [...prev, data.message]); } catch (err) {
setMessages(prev => [
...prev,
{ role: 'assistant', content: 'Sorry, something went wrong. Please try again.' }
]);
} finally {
setIsLoading(false);
}
}; const handleKeyDown = (e) => {
// Send on Enter, new line on Shift+Enter
if (e.key === 'Enter' && !e.shiftKey) {
e.preventDefault();
sendMessage();
}
}; const clearChat = () => {
setMessages([
{ role: 'assistant', content: 'Chat cleared! How can I help you?' }
]);
}; return (
<div className="chat-app">
{/* Header */}
<div className="chat-header">
<div className="bot-info">
<div className="bot-avatar">🤖</div>
<div>
<div className="bot-name">AI Assistant</div>
<div className="bot-status">
{isLoading ? 'Typing...' : 'Online'}
</div>
</div>
</div>
<button className="clear-btn" onClick={clearChat}>Clear Chat</button>
</div> {/* Messages */}
<div className="chat-messages">
{messages.map((msg, i) => (
<div key={i} className={`message-row ${msg.role}`}>
{msg.role === 'assistant' && (
<div className="avatar">🤖</div>
)}
<div className={`bubble ${msg.role}`}>
{msg.content}
</div>
{msg.role === 'user' && (
<div className="avatar">👤</div>
)}
</div>
))} {/* Typing indicator */}
{isLoading && (
<div className="message-row assistant">
<div className="avatar">🤖</div>
<div className="bubble assistant typing">
<span></span><span></span><span></span>
</div>
</div>
)} <div ref={bottomRef} />
</div> {/* Input */}
<div className="chat-input-area">
<textarea
className="chat-input"
value={input}
onChange={(e) => setInput(e.target.value)}
onKeyDown={handleKeyDown}
placeholder="Type a message... (Enter to send)"
rows={1}
disabled={isLoading}
/>
<button
className="send-btn"
onClick={sendMessage}
disabled={!input.trim() || isLoading}
>
Send ➤
</button>
</div>
</div>
);
}export default App;
